import { createClient } from '@/lib/supabase/server';
import BookCard from '@/components/books/BookCard';
import { Book } from '@/types';
import { Search, BookOpen } from 'lucide-react';

export const metadata = {
  title: 'Library | Yoga Wisdom Portal',
  description: 'Explore our collection of sacred texts, modern books, and spiritual literature.',
};

export default async function BooksLibraryPage() {
  const supabase = await createClient();
  
  // Fetch published books
  const { data: books, error } = await supabase
    .from('books')
    .select('*')
    .eq('status', 'published')
    .order('created_at', { ascending: false });

  if (error) {
    console.error('Error fetching books:', error);
  }

  return (
    <div className="min-h-screen bg-[#FAFAF7] pt-24 pb-20">
      <div className="container mx-auto px-4">
        {/* Header */}
        <div className="mb-16 max-w-3xl">
          <h1 className="text-4xl md:text-5xl font-bold font-[family-name:var(--font-cormorant)] text-[#2D5A3D] mb-6">
            The Sacred Library
          </h1>
          <p className="text-lg text-[#8C8B84] text-body">
            Discover profound wisdom through our curated collection of books. 
            From ancient scriptures to contemporary reflections, explore texts that illuminate the path of yoga.
          </p>
        </div>

        {/* Filters and Search Bar (Static for now, will be interactive client-side component later) */}
        <div className="flex flex-col md:flex-row gap-4 mb-12 items-center justify-between bg-white p-4 rounded-2xl shadow-sm border border-[#2D5A3D]/5">
          <div className="relative w-full md:w-96">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-[#8C8B84]" size={20} />
            <input 
              type="text" 
              placeholder="Search by title, author, or keyword..." 
              className="w-full pl-12 pr-4 py-3 bg-[#FAFAF7] rounded-xl focus:outline-none focus:ring-2 focus:ring-[#E8852A]/50 transition-all font-body"
            />
          </div>
          
          <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0 hide-scrollbar">
            <button className="px-6 py-2 rounded-full bg-[#2D5A3D] text-white font-medium whitespace-nowrap">
              All Books
            </button>
            <button className="px-6 py-2 rounded-full bg-[#FAFAF7] text-[#8C8B84] hover:text-[#1C1C1A] hover:bg-[#E8852A]/10 transition-colors font-medium whitespace-nowrap">
              Philosophy
            </button>
            <button className="px-6 py-2 rounded-full bg-[#FAFAF7] text-[#8C8B84] hover:text-[#1C1C1A] hover:bg-[#E8852A]/10 transition-colors font-medium whitespace-nowrap">
              Practice
            </button>
            <button className="px-6 py-2 rounded-full bg-[#FAFAF7] text-[#8C8B84] hover:text-[#1C1C1A] hover:bg-[#E8852A]/10 transition-colors font-medium whitespace-nowrap">
              Sanskrit Texts
            </button>
          </div>
        </div>

        {/* Books Grid */}
        {books && books.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
            {books.map((book: Book) => (
              <BookCard key={book.id} book={book} />
            ))}
          </div>
        ) : (
          <div className="text-center py-32 bg-white rounded-3xl border border-[#2D5A3D]/5 shadow-sm">
            <div className="w-16 h-16 rounded-full bg-[#E8852A]/10 text-[#E8852A] flex items-center justify-center mx-auto mb-4">
              <BookOpen size={32} />
            </div>
            <h3 className="text-2xl font-bold font-[family-name:var(--font-cormorant)] text-[#2D5A3D] mb-2">
              Library is Empty
            </h3>
            <p className="text-[#8C8B84]">
              We are currently curating our collection. Please check back soon.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
