import Link from 'next/link';
import { Book as BookType } from '@/types';
import { BookOpen, Sparkles } from 'lucide-react';

interface BookCardProps {
  book: BookType;
}

export default function BookCard({ book }: BookCardProps) {
  return (
    <Link href={`/books/${book.slug}`} className="group h-full">
      <div className="bg-white rounded-2xl overflow-hidden border border-[#2D5A3D]/10 shadow-sm hover:shadow-xl transition-all duration-300 hover:-translate-y-1 h-full flex flex-col">
        {/* Cover Image Placeholder if no cover_url */}
        <div className="aspect-[2/3] w-full bg-[#FAFAF7] relative border-b border-[#2D5A3D]/5 overflow-hidden">
          {book.cover_url ? (
            // eslint-disable-next-line @next/next/no-img-element
            <img 
              src={book.cover_url} 
              alt={book.title} 
              className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
            />
          ) : (
            <div className="absolute inset-0 flex flex-col items-center justify-center text-[#2D5A3D]/20 p-6 text-center">
              <BookOpen size={48} className="mb-4" />
              <span className="font-[family-name:var(--font-cormorant)] text-xl font-medium leading-tight">
                {book.title}
              </span>
            </div>
          )}
          
          {/* AI Badge */}
          {book.summary_ai && (
            <div className="absolute top-4 right-4 bg-white/90 backdrop-blur-sm text-[#E8852A] px-3 py-1 rounded-full text-xs font-medium flex items-center gap-1 shadow-sm">
              <Sparkles size={12} />
              AI Enhanced
            </div>
          )}
        </div>

        <div className="p-6 flex-grow flex flex-col">
          <div className="flex flex-wrap gap-2 mb-3">
            <span className="text-xs font-medium px-2 py-1 bg-[#2D5A3D]/5 text-[#2D5A3D] rounded-full uppercase tracking-wider">
              {book.language}
            </span>
            {book.genre && (
              <span className="text-xs font-medium px-2 py-1 bg-[#E8852A]/5 text-[#E8852A] rounded-full uppercase tracking-wider">
                {book.genre}
              </span>
            )}
          </div>
          
          <h3 className="text-xl font-bold font-[family-name:var(--font-cormorant)] text-[#1C1C1A] mb-2 line-clamp-2 group-hover:text-[#E8852A] transition-colors">
            {book.title}
          </h3>
          
          {book.author && (
            <p className="text-[#8C8B84] text-sm mb-4">
              By {book.author}
            </p>
          )}

          <p className="text-[#8C8B84] text-sm line-clamp-3 mt-auto">
            {book.summary || book.summary_ai || "No summary available."}
          </p>
        </div>
      </div>
    </Link>
  );
}
